```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return conn_result.error();
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return transaction_result.error();
  }
  auto transaction = transaction_result.value();

  // Create delete statement with condition
  using namespace sqlgen::literals;
  auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");

  // Execute the delete operation
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    // If delete fails, we still commit the transaction as per requirement
  }

  // Commit the transaction and return result
  auto commit_result = transaction->commit();
  return commit_result;
}

} // namespace delete_inactive_users
```

