 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform upsert operation using sqlgen's write API with upsert modifier
  auto upsert_result = (sqlgen::write(conn, items) | sqlgen::upsert);

  // Verify upsert operation success
  if (!upsert_result) {
    return false;
  }

  // Read back the items to verify upsert behavior
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);

  // Check if read operation was successful and data matches
  if (!read_result || read_result->size() != items.size()) {
    return false;
  }

  // Compare each field of the upserted items
  for (size_t i = 0; i < items.size(); ++i) {
    if (read_result->at(i).item_id != items[i].item_id ||
        read_result->at(i).name != items[i].name ||
        read_result->at(i).quantity != items[i].quantity) {
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
