  create_table<Child>(conn);

  auto parent = Parent{.parent_id = 1, .name = "Test Parent"};
  auto children = std::vector<Child>{
      {.child_id = 1, .parent_id = 1, .note = "First Child"},
      {.child_id = 2, .parent_id = 1, .note = "Second Child"},
