  std::vector<TimeMetrics> metrics;
  for (auto& row : result) {
    metrics.emplace_back(
        TimeMetrics{
            .project_id = row.project_id,
            .name = row.name,
            .day = row.day,
            .month = row.month,
            .year = row.year,
            .hour = row.hour,
            .minute = row.minute,
            .second = row.second,
            .duration_days = row.duration_days
